const express = require('express');
const axios = require('axios');

const app = express();
app.use(express.json());

const PORT = process.env.PORT || 3000;

app.post('/verify-license', async (req, res) => {
  const { license_number } = req.body;

  if (!license_number) {
    return res.status(400).json({ error: 'license_number is required' });
  }

  const appId = process.env.PREMBLY_APP_ID;
  const apiKey = process.env.PREMBLY_API_KEY;

  if (!appId || !apiKey) {
    return res.status(500).json({ error: 'Prembly configuration is missing' });
  }

  try {
    const response = await axios.post(
      'https://api.prembly.com/verification/drivers_license',
      { number: license_number },
      {
        headers: {
          'app-id': appId,
          'x-api-key': apiKey,
        },
      }
    );

    res.json(response.data);
  } catch (error) {
    console.error('Error verifying license:', error.response ? error.response.data : error.message);
    const status = error.response ? error.response.status : 500;
    const data = error.response ? error.response.data : { error: 'Internal Server Error' };
    res.status(status).json(data);
  }
});

app.listen(PORT, () => {
  console.log(`Server is running on port ${PORT}`);
});

